	@Test
	public void testQueryLevelValuesJoinRetainsGroupedRowsWithUnboundJoinVariable() throws QueryEvaluationException {
		BindingSetAssignment groupedInput = new BindingSetAssignment();
		groupedInput.setBindingSets(List.of(
				bindingSet("x", 1),
				bindingSet("x", 1),
				bindingSet("x", 2),
				bindingSet("z", 10),
				bindingSet("z", 10),
				bindingSet("z", 20)));

		Group group = new Group(groupedInput);
		group.addGroupBindingName("x");
		group.addGroupElement(new GroupElem("count", new Count(new ValueConstant(vf.createLiteral(1)))));

		BindingSetAssignment values = new BindingSetAssignment();
		values.setBindingSets(List.of(
				bindingSet("x", 1, "z", 10),
				bindingSet("x", 2, "z", 20)));

		Join join = new Join(group, values);
		join.setVariableScopeChange(true);

		List<String> actual = new ArrayList<>();
		try (CloseableIteration<BindingSet> iter = evaluator.evaluate(join, EmptyBindingSet.getInstance())) {
			while (iter.hasNext()) {
				BindingSet bindingSet = iter.next();
				actual.add(String.format("x=%s count=%s z=%s",
						valueString(bindingSet, "x"),
						valueString(bindingSet, "count"),
						valueString(bindingSet, "z")));
			}
		}

		Collections.sort(actual);
		assertEquals(List.of(
				"x=1 count=2 z=10",
				"x=1 count=3 z=10",
				"x=2 count=1 z=20",
				"x=2 count=3 z=20"), actual);
	}

