	@Test
	public void testParsedQueryLevelValuesAfterGroupByPreservesAllGroups() throws Exception {
		String query = String.join("\n",
				"PREFIX : <http://example.com/>",
				"SELECT ?x (COUNT(*) AS ?count) WHERE {",
				"  { ?s :p ?x } UNION { ?s :q ?z }",
				"}",
				"GROUP BY ?x",
				"ORDER BY COALESCE(STR(?x), \"\") COALESCE(STR(?count), \"\")",
				"VALUES (?x ?z) { (1 10) (2 20) }");

		List<Statement> statements = List.of(
				vf.createStatement(vf.createIRI("http://example.com/a"), vf.createIRI("http://example.com/p"),
						vf.createLiteral("1", CoreDatatype.XSD.INTEGER)),
				vf.createStatement(vf.createIRI("http://example.com/b"), vf.createIRI("http://example.com/p"),
						vf.createLiteral("1", CoreDatatype.XSD.INTEGER)),
				vf.createStatement(vf.createIRI("http://example.com/c"), vf.createIRI("http://example.com/p"),
						vf.createLiteral("2", CoreDatatype.XSD.INTEGER)),
				vf.createStatement(vf.createIRI("http://example.com/d"), vf.createIRI("http://example.com/q"),
						vf.createLiteral("10", CoreDatatype.XSD.INTEGER)),
				vf.createStatement(vf.createIRI("http://example.com/e"), vf.createIRI("http://example.com/q"),
						vf.createLiteral("20", CoreDatatype.XSD.INTEGER)),
				vf.createStatement(vf.createIRI("http://example.com/f"), vf.createIRI("http://example.com/q"),
						vf.createLiteral("10", CoreDatatype.XSD.INTEGER)));

		TripleSource tripleSource = new TripleSource() {
			@Override
			public ValueFactory getValueFactory() {
				return vf;
			}

			@Override
			public CloseableIteration<? extends Statement> getStatements(Resource subj, IRI pred, Value obj,
					Resource... contexts) {
				return new CloseableIteratorIteration<>(statements.stream()
						.filter(statement -> subj == null || subj.equals(statement.getSubject()))
						.filter(statement -> pred == null || pred.equals(statement.getPredicate()))
						.filter(statement -> obj == null || obj.equals(statement.getObject()))
						.collect(Collectors.toList())
						.iterator());
			}
		};

		EvaluationStrategy parsedEvaluator = new StrictEvaluationStrategy(tripleSource, null);
		ParsedQuery parsedQuery = new SPARQLParser().parseQuery(query, null);
		Join join = findFirstNode(parsedQuery.getTupleExpr(), Join.class);

		List<String> joinResults = new ArrayList<>();
		try (CloseableIteration<BindingSet> iter = parsedEvaluator.evaluate(join, EmptyBindingSet.getInstance())) {
			while (iter.hasNext()) {
				BindingSet bindingSet = iter.next();
				joinResults.add(String.format("x=%s count=%s z=%s",
						valueString(bindingSet, "x"),
						valueString(bindingSet, "count"),
						valueString(bindingSet, "z")));
			}
		}

		Collections.sort(joinResults);
		assertEquals(List.of(
				"x=1 count=2 z=10",
				"x=1 count=3 z=10",
				"x=2 count=1 z=20",
				"x=2 count=3 z=20"), joinResults);

		List<String> actual = new ArrayList<>();
		try (CloseableIteration<BindingSet> iter = parsedEvaluator.evaluate(parsedQuery.getTupleExpr(),
				EmptyBindingSet.getInstance())) {
			while (iter.hasNext()) {
				BindingSet bindingSet = iter.next();
				actual.add(String.format("x=%s count=%s",
						valueString(bindingSet, "x"),
						valueString(bindingSet, "count")));
			}
		}

		Collections.sort(actual);
		assertEquals(List.of(
				"x=1 count=2",
				"x=1 count=3",
				"x=2 count=1",
				"x=2 count=3"), actual);
	}

	private BindingSet bindingSet(String name, int value) {
		QueryBindingSet bindingSet = new QueryBindingSet();
		bindingSet.addBinding(name, vf.createLiteral(value));
		return bindingSet;
	}

	private BindingSet bindingSet(String name1, int value1, String name2, int value2) {
		QueryBindingSet bindingSet = new QueryBindingSet();
		bindingSet.addBinding(name1, vf.createLiteral(value1));
		bindingSet.addBinding(name2, vf.createLiteral(value2));
		return bindingSet;
	}

	private String valueString(BindingSet bindingSet, String name) {
		Value value = bindingSet.getValue(name);
		return value == null ? "UNBOUND" : value.stringValue();
	}

	private <T extends QueryModelNode> T findFirstNode(QueryModelNode root, Class<T> type) {
		Deque<QueryModelNode> stack = new ArrayDeque<>();
		stack.push(root);

		while (!stack.isEmpty()) {
			QueryModelNode current = stack.pop();
			if (type.isInstance(current)) {
				return type.cast(current);
			}
			if (current instanceof TupleExpr) {
				List<TupleExpr> children = new ArrayList<>();
				((TupleExpr) current).visitChildren(
						new org.eclipse.rdf4j.query.algebra.helpers.AbstractQueryModelVisitor<RuntimeException>() {
							@Override
							public void meetNode(QueryModelNode node) {
								if (node instanceof TupleExpr) {
									children.add((TupleExpr) node);
								}
							}
						});
				for (int i = children.size() - 1; i >= 0; i--) {
					stack.push(children.get(i));
				}
			}
		}

		return null;
	}
